import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.io.*;

public class XSSSecureCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS attack!')</script>";
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String encodedInput = codec.encodeForHTML(userInput);
        String output = "<html><body>Welcome, " + encodedInput + "</body></html>";

        try {
            File file = new File("output.html");
            FileWriter writer = new FileWriter(file);
            writer.write(output);
            writer.close();
            System.out.println("Output written to file: " + file.getAbsolutePath());
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

